// Google Sheets rows come as flat objects with column headers as keys
const items = $input.all();
const rows = items.map(item => item.json);

// Filter out empty rows
const validRows = rows.filter(r => r.email || r.Email);

// Normalize column names to lowercase
const normalizedRows = validRows.map(r => {
  const normalized = {};
  for (const [key, value] of Object.entries(r)) {
    normalized[key.toLowerCase().replace(/\s+/g, '_')] = value;
  }
  return normalized;
});

// TODO: Replace collection IDs with your actual IDs
// Find them via GET /api/v1/collections
const payload = {
  source: 'Google Sheets',
  mapping: {
    entityType: 'contact',
    email: 'email',
    runName: 'n8n-gsheets-import-' + Date.now(),
    properties: {
      // Adjust sourceField names to match your sheet column headers (lowercased)
      email:      { sourceField: 'email',       collectionId: 'YOUR_STANDARD_COL_ID', collectionName: 'Contacts Standard Schema' },
      first_name: { sourceField: 'first_name',  collectionId: 'YOUR_STANDARD_COL_ID', collectionName: 'Contacts Standard Schema' },
      last_name:  { sourceField: 'last_name',   collectionId: 'YOUR_STANDARD_COL_ID', collectionName: 'Contacts Standard Schema' },
      company:    { sourceField: 'company',     collectionId: 'YOUR_STANDARD_COL_ID', collectionName: 'Contacts Standard Schema' },
      phone:      { sourceField: 'phone',       collectionId: 'YOUR_STANDARD_COL_ID', collectionName: 'Contacts Standard Schema' },
      // Add extractMemories: true for unstructured fields
      notes: {
        sourceField: 'notes',
        collectionId: 'YOUR_GENERATED_COL_ID',
        collectionName: 'Generated Content',
        extractMemories: true,
      },
    },
  },
  rows: normalizedRows,
  chunkSize: 1,
};

console.log(`Prepared ${normalizedRows.length} rows for batch memorize`);
return [{ json: payload }];
